5	// CLI integration tests: spawn src/cli.ts, write a JSON scenario to stdin,
6	// read the JSON results from stdout, and assert on the process exit code.
7	
8	const cliPath = fileURLToPath(new URL("./cli.ts", import.meta.url));
9	
10	function runCli(scenario: unknown): {
11	  status: number | null;
12	  stdout: string;
13	  stderr: string;
14	} {
15	  const result = spawnSync("npx", ["tsx", cliPath], {
16	    input: JSON.stringify(scenario),
17	    encoding: "utf8",
18	  });
19	  return {
20	    status: result.status,
21	    stdout: result.stdout,
22	    stderr: result.stderr,
23	  };
24	}
25	
26	describe("claim-office CLI (stdin -> stdout)", () => {
27	  it("should read a scenario from stdin and write a results JSON to stdout", () => {
28	    const scenario = {
29	      customer: { yearsWithMHPCO: 5 },
30	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
31	    };
32	
33	    const { status, stdout } = runCli(scenario);
